#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char s[20];
    while(T--){
        scanf("%s", s);
        int cnt=0;
        for(int i=0; s[i]; ++i) if(s[i]=='4') ++cnt;
        printf("%d\n", cnt);
    }
    return 0;
}

